import React, { useEffect, useState } from 'react';
import { BrowserRouter as Router, Route, Redirect } from 'react-router-dom';

const CLIENT_ID = 'YOUR_CLIENT_ID';
const REDIRECT_URI = 'http://localhost:3000/callback';
const AUTHORIZATION_ENDPOINT = 'https://authorization-server.com/auth';
const SCOPES = 'openid profile email';

const App = () => {
  return (
    <Router>
      <Route path="/" exact component={Home} />
      <Route path="/callback" component={Callback} />
    </Router>
  );
};

const Home = () => {
  const handleLogin = () => {
    const authUrl = `${AUTHORIZATION_ENDPOINT}?response_type=token&client_id=${encodeURIComponent(CLIENT_ID)}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}&scope=${encodeURIComponent(SCOPES)}`;
    window.location.href = authUrl;
  };

  return (
    <div>
      <h1>Welcome to the App</h1>
      <button onClick={handleLogin}>Login with OAuth</button>
    </div>
  );
};

const Callback = () => {
  const [accessToken, setAccessToken] = useState(null);

  useEffect(() => {
    const hash = window.location.hash;
    if (hash) {
      const params = new URLSearchParams(hash.substring(1));
      const token = params.get('access_token');
      if (token) {
        setAccessToken(token);
        // Securely store the token in memory or a secure storage
      }
    }
  }, []);

  if (!accessToken) {
    return <Redirect to="/" />;
  }

  return (
    <div>
      <h1>Authenticated</h1>
      <p>Access Token: {accessToken}</p>
    </div>
  );
};

export default App;